int numSteps(char* s) {
    int steps = 0;
    int len = strlen(s);
    char* str = (char*)malloc(len + 2);
    strcpy(str, s);

    while (strcmp(str, "1") != 0) {
        steps++;
        int current_len = strlen(str);
        if (str[current_len - 1] == '0') {
            // 偶数的情况
            str[current_len - 1] = '\0';
        } else {
            // 第一步：找出最低位的 0
            // 第二步：把这个 0 变成 1，并将后面所有的 1 变成 0，这样就实现了 +1
            // 特别地，如果 s 中全是 1，那么会有额外的进位
            bool found = false;
            for (int i = current_len - 1; i >= 0; --i) {
                if (str[i] == '1') {
                    str[i] = '0';
                    if (i == 0) {
                        memmove(str + 1, str, current_len + 1);
                        str[0] = '1';
                        found = true;
                        break;
                    }
                } else {
                    str[i] = '1';
                    found = true;
                    break;
                }
            }
            if (!found) {
                memmove(str + 1, str, current_len + 1);
                str[0] = '1';
            }
        }
    }

    free(str);
    return steps;
}
